const itemBasePremiums: Record<Item["type"], number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  component: 25,
};

const calculateComponentPremium = (count?: number): number => {
  const isTripleComponentDiscount = count === 3;
  return isTripleComponentDiscount ? 35 : 25;
};

export function quote(items: Item[]): number {
  return items.reduce((total, item) => {
    const itemPremium =
      item.type === "component" ? calculateComponentPremium(item.count) : itemBasePremiums[item.type];
    return total + itemPremium;
  }, 0);
}

